import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getMatches, createMatch, updateScore, getTeams } from '../services/api';
import { useAuth } from '../context/AuthContext';

export default function AdminMatches() {
  const { id } = useParams();
  const [matches, setMatches] = useState([]);
  const [teams, setTeams] = useState([]);
  const [filter, setFilter] = useState('ALL');
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({ matchNumber: '', venue: '', matchDateTime: '', team1Id: '', team2Id: '', overs: 20 });
  const [saving, setSaving] = useState(false);
  const { isScorer } = useAuth();

  useEffect(() => {
    load();
    getTeams(id).then(r => setTeams(r.data));
  }, [id]);

  const load = () => getMatches(id).then(r => setMatches(r.data));

  const handleCreate = async (e) => {
    e.preventDefault(); setSaving(true);
    await createMatch({ ...form, tournamentId: +id, overs: +form.overs, team1Id: +form.team1Id, team2Id: +form.team2Id, matchNumber: +form.matchNumber });
    setShowCreate(false);
    setForm({ matchNumber: '', venue: '', matchDateTime: '', team1Id: '', team2Id: '', overs: 20 });
    load(); setSaving(false);
  };

  const quickStatus = async (match, status) => {
    await updateScore(match.id, { team: 'team1', score: match.team1Score || 0, wickets: match.team1Wickets || 0, overs: match.team1Overs || 0, status });
    load();
  };

  const filtered = filter === 'ALL' ? matches : matches.filter(m => m.status === filter);

  const TEAM_COLORS = ['#d4a017', '#2979ff', '#00c853', '#ff3b3b', '#7c4dff', '#00e5ff'];
  const teamColor = (tid) => {
    const idx = teams.findIndex(t => t.id === tid);
    return TEAM_COLORS[idx % TEAM_COLORS.length] || 'var(--text-3)';
  };

  return (
    <div>
      <div className="top-bar">
        <div className="top-bar-left">
          <div className="top-bar-title">Match Management</div>
        </div>
        <div className="top-bar-right">
          {isScorer && (
            <button className="btn btn-primary" onClick={() => setShowCreate(true)}>+ Schedule Match</button>
          )}
        </div>
      </div>

      <div className="page-content">
        <div className="breadcrumb">
          <Link to="/admin/dashboard">Admin</Link>
          <span className="breadcrumb-sep">/</span>
          <span>Matches</span>
        </div>

        <div className="tabs">
          {['ALL', 'LIVE', 'SCHEDULED', 'COMPLETED'].map(f => (
            <button key={f} className={`tab ${filter === f ? 'active' : ''}`} onClick={() => setFilter(f)}>
              {f === 'ALL' ? 'All' : f.charAt(0) + f.slice(1).toLowerCase()}
              {f !== 'ALL' && (
                <span style={{ marginLeft: 6, background: 'rgba(255,255,255,0.08)', padding: '1px 6px', borderRadius: 10, fontSize: 10 }}>
                  {matches.filter(m => m.status === f).length}
                </span>
              )}
            </button>
          ))}
        </div>

        {filtered.length === 0 ? (
          <div className="card"><div className="empty-state">
            <div className="empty-state-icon">🎯</div>
            <h3>No matches found</h3>
            <p>Schedule a new match to get started</p>
          </div></div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {filtered.map(m => (
              <div key={m.id} className={`match-card ${m.status === 'LIVE' ? 'live' : ''}`}>
                <div className="match-card-top">
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span className="match-number">Match #{m.matchNumber}</span>
                    {m.matchDateTime && (
                      <span style={{ fontSize: 11, color: 'var(--text-3)' }}>
                        {new Date(m.matchDateTime).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' })}
                      </span>
                    )}
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span className="match-venue">📍 {m.venue}</span>
                    {m.status === 'LIVE' && <span className="badge badge-live">Live</span>}
                    {m.status === 'COMPLETED' && <span className="badge badge-completed">Final</span>}
                    {m.status === 'SCHEDULED' && <span className="badge badge-scheduled">Upcoming</span>}
                  </div>
                </div>

                <div className="match-teams">
                  <div className="match-team home">
                    <div className="team-name-row">
                      <div className="team-color-dot" style={{ background: teamColor(m.team1Id) }} />
                      <span className="team-short">{m.team1Name}</span>
                    </div>
                    {m.team1Score != null ? (
                      <span className="team-score">{m.team1Score}/{m.team1Wickets || 0}</span>
                    ) : <span style={{ color: 'var(--text-3)', fontSize: 13 }}>Yet to bat</span>}
                    {m.team1Overs > 0 && <span className="team-overs">({m.team1Overs} ov)</span>}
                  </div>
                  <div className="match-vs">VS</div>
                  <div className="match-team away" style={{ alignItems: 'flex-end' }}>
                    <div className="team-name-row" style={{ flexDirection: 'row-reverse' }}>
                      <div className="team-color-dot" style={{ background: teamColor(m.team2Id) }} />
                      <span className="team-short">{m.team2Name}</span>
                    </div>
                    {m.team2Score != null ? (
                      <span className="team-score">{m.team2Score}/{m.team2Wickets || 0}</span>
                    ) : <span style={{ color: 'var(--text-3)', fontSize: 13 }}>Yet to bat</span>}
                    {m.team2Overs > 0 && <span className="team-overs">({m.team2Overs} ov)</span>}
                  </div>
                </div>

                <div className="match-card-footer">
                  <div>
                    {m.result && <span className="match-result">🏆 {m.result}</span>}
                    {m.tossWinnerName && <span style={{ fontSize: 11, color: 'var(--text-3)', marginLeft: m.result ? 12 : 0 }}>🪙 {m.tossWinnerName} won toss</span>}
                  </div>
                  <div style={{ display: 'flex', gap: 6 }}>
                    <Link to={`/matches/${m.id}/scorecard`} className="btn btn-ghost btn-sm">Scorecard</Link>
                    {isScorer && (
                      <>
                        {m.status === 'SCHEDULED' && (
                          <button className="btn btn-success btn-sm" onClick={() => quickStatus(m, 'LIVE')}>▶ Start</button>
                        )}
                        <Link to={`/admin/matches/${m.id}/score`} className="btn btn-primary btn-sm">
                          {m.status === 'LIVE' ? '📡 Score Live' : '⚙ Manage'}
                        </Link>
                      </>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Create Match Modal */}
      {showCreate && (
        <div className="modal-backdrop" onClick={e => e.target === e.currentTarget && setShowCreate(false)}>
          <div className="modal modal-md">
            <div className="modal-header">
              <div className="modal-title">Schedule New Match</div>
              <button className="close-btn" onClick={() => setShowCreate(false)}>×</button>
            </div>
            <form onSubmit={handleCreate}>
              <div className="modal-body">
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Match Number</label>
                    <input className="form-input" type="number" min="1" placeholder="e.g. 1" required value={form.matchNumber} onChange={e => setForm(f => ({ ...f, matchNumber: e.target.value }))} />
                  </div>
                  <div className="form-group">
                    <label className="form-label">Overs</label>
                    <input className="form-input" type="number" min="1" max="50" value={form.overs} onChange={e => setForm(f => ({ ...f, overs: e.target.value }))} />
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Venue</label>
                  <input className="form-input" placeholder="e.g. Eden Gardens, Kolkata" required value={form.venue} onChange={e => setForm(f => ({ ...f, venue: e.target.value }))} />
                </div>
                <div className="form-group">
                  <label className="form-label">Match Date & Time</label>
                  <input className="form-input" type="datetime-local" value={form.matchDateTime} onChange={e => setForm(f => ({ ...f, matchDateTime: e.target.value }))} />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Team 1</label>
                    <select className="form-select" required value={form.team1Id} onChange={e => setForm(f => ({ ...f, team1Id: e.target.value }))}>
                      <option value="">— Select team —</option>
                      {teams.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Team 2</label>
                    <select className="form-select" required value={form.team2Id} onChange={e => setForm(f => ({ ...f, team2Id: e.target.value }))}>
                      <option value="">— Select team —</option>
                      {teams.filter(t => t.id !== +form.team1Id).map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </select>
                  </div>
                </div>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-ghost" onClick={() => setShowCreate(false)}>Cancel</button>
                <button type="submit" className="btn btn-primary" disabled={saving}>{saving ? 'Scheduling...' : 'Schedule Match'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
